const clickSound=new Audio("../Minimal Click.wav");clickSound.preload="none",clickSound.volume=.5;const backgroundMusic=document.getElementById("backgroundMusic");let musicState={isPlaying:!1,hasInteracted:!1};function updateMusicUI(){const t=document.getElementById("musicToggle");if(!t)return;const c=t.querySelector(".music-icon"),e=t.querySelector(".music-text");musicState.isPlaying?(c.textContent="🎵",e.textContent="Music ON",e.classList.remove("text-red-400"),e.classList.add("text-green-400")):(c.textContent="🔇",e.textContent="Music OFF",e.classList.remove("text-green-400"),e.classList.add("text-red-400"))}function toggleMusic(){backgroundMusic.paused?backgroundMusic.play().then(()=>{musicState.isPlaying=!0,updateMusicUI()}).catch(()=>{musicState.isPlaying=!1,updateMusicUI()}):(backgroundMusic.pause(),musicState.isPlaying=!1,updateMusicUI())}function startMusicOnInteraction(){musicState.hasInteracted||backgroundMusic.play().then(()=>{musicState.isPlaying=!0,musicState.hasInteracted=!0,updateMusicUI()}).catch(()=>{musicState.isPlaying=!1,musicState.hasInteracted=!0,updateMusicUI()})}function playClickSound(){try{clickSound.currentTime=0,clickSound.play().catch(()=>{})}catch{}}document.addEventListener("DOMContentLoaded",function(){updateMusicUI();let t=!0;document.addEventListener("click",function(c){t&&(startMusicOnInteraction(),t=!1);const e=c.target;("BUTTON"===e.tagName||"A"===e.tagName||e.closest("button")||e.closest("a"))&&playClickSound()});const c=document.getElementById("musicToggle");c&&c.addEventListener("click",function(t){t.stopPropagation(),toggleMusic(),musicState.hasInteracted=!0}),clickSound.load()}),window.clickSound={play:playClickSound,audio:clickSound};